    t={"task_version":1,"task_type":"simulate_market_v1","market_path":str(q/"market.parquet"),"entry_intent_path":str(q/"entry.parquet"),"exit_intent_path":str(q/"exit.parquet"),"output_path":str(q/"trades.parquet"),"config":{"schema_version":1,"side":side,"price_column":"open","entry_column":"entry_intent","exit_column":"exit_intent","position_policy":"one_at_a_time","terminal_policy":"leave_open","initial_bracket":{"model":"fixed_price_offsets_v1","stop_offset":1.,"target_offset":2.,"output_path":str(q/"brackets.parquet")},"initial_bracket_execution":{"model":"ohlc_unambiguous_v1","event_output_path":str(q/"events.parquet")}}};(q/"task.json").write_text(json.dumps(t));r=subprocess.run([str(binary),str(q/"task.json")],capture_output=True,text=True);return r,q
