 def test_closed_trade_metrics_cli_evidence(self):
  import pyarrow as pa, pyarrow.parquet as pq
  root=Path(__file__).resolve().parents[1]; binary=root/"engine"/"target"/"debug"/"labengine"
  with tempfile.TemporaryDirectory() as d:
   p=Path(d)
   def ledger(path,pnls):
    n=len(pnls); pq.write_table(pa.table({"trade_id":pa.array(range(1,n+1),type=pa.uint64()),"side":pa.array(["long"]*n,type=pa.string()),"entry_timestamp":pa.array([f"2040.01.01 00:{i:02}" for i in range(n)],type=pa.string()),"exit_timestamp":pa.array([f"2040.01.01 01:{i:02}" for i in range(n)],type=pa.string()),"entry_index":pa.array([i*2 for i in range(n)],type=pa.uint64()),"exit_index":pa.array([i*2+1 for i in range(n)],type=pa.uint64()),"entry_price":pa.array([10.]*n,type=pa.float64()),"exit_price":pa.array([10.+x for x in pnls],type=pa.float64()),"bars_held":pa.array([1]*n,type=pa.uint64()),"gross_pnl_per_unit":pa.array(pnls,type=pa.float64())}),path)
   def run(path,name):
    q=p/name;q.mkdir(); out=q/"metrics.json"; task={"task_version":1,"task_type":"compute_closed_trade_metrics_v1","input_path":str(path),"output_path":str(out)}; spec=q/"task.json"; spec.write_text(json.dumps(task)); r=subprocess.run([str(binary),str(spec)],capture_output=True,text=True); return r,out,json.loads(r.stdout) if r.returncode==0 else None
   mixed=p/"mixed.parquet"; ledger(mixed,[2.,-1.,0.,3.,-2.]); a,oa,sa=run(mixed,"mixed-a"); b,ob,sb=run(mixed,"mixed-b"); m=sa["metrics"]; self.assertEqual((m["trade_count"],m["win_count"],m["loss_count"],m["breakeven_count"],m["gross_profit"],m["gross_loss_abs"],m["net_gross_pnl"],m["average_trade"],m["win_rate"],m["average_win"],m["average_loss_abs"]),(5,2,2,1,5.,3.,2.,.4,.4,2.5,1.5)); self.assertAlmostEqual(m["profit_factor"],5./3.); self.assertEqual((json.loads(oa.read_text()),sa["metrics_semantic_identity"]),(json.loads(ob.read_text()),sb["metrics_semantic_identity"]))
   for name,pnls,expect in [("empty",[],(None,None,None)),("winners",[1.,2.],(1.5,None,None)),("losers",[-1.,-2.],(None,1.5,0.))]:
    x=p/(name+".parquet"); ledger(x,pnls); r,o,s=run(x,name); z=s["metrics"]; self.assertEqual((z["average_win"],z["average_loss_abs"],z["profit_factor"]),expect); self.assertEqual((z["trade_count"],z["gross_profit"],z["gross_loss_abs"]),(len(pnls),sum(v for v in pnls if v>0),-sum(v for v in pnls if v<0)))
   changed=p/"changed.parquet"; ledger(changed,[2.,-1.,0.,3.,-3.]); r,o,sc=run(changed,"changed"); self.assertEqual((sc["metrics"]["gross_loss_abs"],sc["metrics"]["net_gross_pnl"],sc["metrics"]["average_loss_abs"]),(4.,1.,2.)); self.assertNotEqual(sc["metrics_semantic_identity"],sa["metrics_semantic_identity"])
   reordered=p/"reordered.parquet"; ledger(reordered,[-1.,2.,0.,3.,-2.]); r,o,sr=run(reordered,"reordered"); self.assertEqual(sr["metrics"],m); self.assertNotEqual(sr["metrics_semantic_identity"],sa["metrics_semantic_identity"])
   fixtures=root/"engine/labengine/tests/fixtures"; names=["phase2_cross_task.json","phase2_ast_evaluate_task.json","phase2_entry_intent_task.json","phase2_exit_intent_task.json","phase2_market_simulator_task.json"]; tasks=[json.loads((fixtures/name).read_text()) for name in names]; paths=[p/(name+".parquet") for name in ["cross","signal","entry-intent","exit-intent","committed-trades"]]; tasks[0]["input_path"]=str(root/tasks[0]["input_path"]); tasks[0]["output_path"]=str(paths[0]); tasks[1]["input_path"]=str(paths[0]); tasks[1]["output_path"]=str(paths[1]); tasks[2]["input_path"]=str(paths[1]); tasks[2]["output_path"]=str(paths[2]); tasks[3]["input_path"]=str(paths[1]); tasks[3]["output_path"]=str(paths[3]); tasks[4]["market_path"]=str(root/tasks[4]["market_path"]); tasks[4]["entry_intent_path"]=str(paths[2]); tasks[4]["exit_intent_path"]=str(paths[3]); tasks[4]["output_path"]=str(paths[4]);
   for i,task in enumerate(tasks): spec=p/(f"committed-{i}.json"); spec.write_text(json.dumps(task)); subprocess.run([str(binary),str(spec)],check=True,capture_output=True,text=True)
   r,o,s=run(paths[4],"committed"); z=s["metrics"]; self.assertEqual((z["trade_count"],z["win_count"],z["loss_count"],z["breakeven_count"],z["gross_profit"],z["win_rate"],z["average_win"],z["profit_factor"]),(4,0,4,0,0.,0.,None,0.)); self.assertAlmostEqual(z["gross_loss_abs"],.0012); self.assertAlmostEqual(z["net_gross_pnl"],-.0012); self.assertAlmostEqual(z["average_trade"],-.0003); self.assertAlmostEqual(z["average_loss_abs"],.0003)
   bad=p/"bad.parquet"; pq.write_table(pa.table({"x":[1]}),bad); r,o,s=run(bad,"schema"); self.assertEqual((r.returncode,r.stdout),(2,"")); self.assertIn("closed-trade ledger schema",r.stderr); self.assertFalse(o.exists())
