   badheld=p/"badheld.parquet"; ledger(badheld,[1.]); t=pq.read_table(badheld); pq.write_table(t.set_column(8,"bars_held",pa.array([2],type=pa.uint64())),badheld); r,o,s=run(badheld,"held"); self.assertEqual((r.returncode,r.stdout),(2,"")); self.assertIn("bars_held",r.stderr); self.assertFalse(o.exists())
